  ('wurzel.steps.decagon.step.DecagonKnowledgeBaseStep', 'DecagonKnowledgeBaseStep', 'wurzel.steps.decagon.step.DecagonKnowledgeBaseStep', $k1eda12389c05497db2ac57f2f86703d6${"additionalProperties": false, "description": "Configuration for the Decagon Knowledge Base connector.\n\nAttributes:\n    API_URL: Base URL for the Decagon API.\n    API_KEY: API key for authentication (required).\n    SOURCE: Source identifier for articles - all created articles will\n        have this source value.\n    TIMEOUT: Request timeout in seconds.\n\nEnvironment Variables (with DECAGONKBSTEP prefix):\n    DECAGONKBSTEP__API_URL: Decagon API base URL\n    DECAGONKBSTEP__API_KEY: API key for authentication (required)\n    DECAGONKBSTEP__SOURCE: Source identifier for articles\n    DECAGONKBSTEP__TIMEOUT: Request timeout in seconds", "properties": {"API_URL": {"default": "https://eu.api.decagon.ai", "description": "Base URL for the Decagon API", "title": "Api Url", "type": "string"}, "API_KEY": {"description": "API key for authentication with Decagon", "format": "password", "title": "Api Key", "type": "string", "writeOnly": true}, "SOURCE": {"default": "Wurzel", "description": "Source identifier for articles", "title": "Source", "type": "string"}, "TIMEOUT": {"default": 120, "description": "Request timeout in seconds", "exclusiveMinimum": 0, "title": "Timeout", "type": "integer"}}, "required": ["API_KEY"], "title": "DecagonSettings", "type": "object"}$k1eda12389c05497db2ac57f2f86703d6$::jsonb, $kd2af8dc23c8b413cb5ffb4e100a799e0${"type": "array", "title": "input", "items": {"description": "A data contract of the input/output of the various pipeline steps representing a document in Markdown format.\n\nThe document consists have the Markdown body (document content) and additional metadata (keywords, url).\nThe metadata is optional.\n\nExample 1 (with metadata):\n```md\n---\nkeywords: \"bread,butter\"\nurl: \"some/file/path.md\"\n---\n# Some title\n\nWith some more text.\n\n## And\n\n- Other\n- [Markdown content](#some-link)\n```\n\nExample 2 (without metadata):\n```md\n# Another title\n\nAnother text.\n```\n\nExample 3 (with extra metadata fields)\n```md\n---\nkeywords: \"bread,butter\"\nurl: \"some/file/path.md\"\nmetadata:\n    token_len: 123\n    char_len: 550\n---\n# Some title\n\nA short text.\n```", "properties": {"md": {"title": "Md", "type": "string"}, "keywords": {"title": "Keywords", "type": "string"}, "url": {"title": "Url", "type": "string"}, "metadata": {"anyOf": [{"type": "string"}, {"type": "null"}], "default": null, "title": "Metadata"}}, "required": ["md", "keywords", "url"], "title": "MarkdownDataContract", "type": "object"}}$kd2af8dc23c8b413cb5ffb4e100a799e0$::jsonb, $k19cf02e7ed474e56842a421556612ed4${"type": "object", "title": "output", "x-wurzel-fqn": "pandera.typing.pandas.DataFrame[wurzel.steps.decagon.data.DecagonArticleResult]"}$k19cf02e7ed474e56842a421556612ed4$::jsonb, nullif('list[wurzel.datacontract.common.MarkdownDataContract]', '')::text, nullif('pandera.typing.pandas.DataFrame[wurzel.steps.decagon.data.DecagonArticleResult]', '')::text, now()),
