  ('wurzel.steps.milvus.step.MilvusConnectorStep', 'MilvusConnectorStep', 'wurzel.steps.milvus.step.MilvusConnectorStep', $kb1670c584e3849768830fe9c4d1e9ef9${"additionalProperties": false, "description": "MilvusSettings is a configuration class for managing settings related to MilvusDB.\n\nAttributes:\n    HOST (str): The hostname or IP address of the Milvus server. Defaults to \"localhost\".\n    PORT (int): The port number for the Milvus server. Must be between 1 and 65535. Defaults to 19530.\n    COLLECTION (str): The name of the collection in MilvusDB.\n    COLLECTION_HISTORY_LEN (int): The length of the collection history. Defaults to 10.\n    SEARCH_PARAMS (dict): Parameters for search operations in MilvusDB. Defaults to {\"metric_type\": \"IP\", \"params\": {}}.\n    INDEX_PARAMS (dict): Parameters for indexing operations in MilvusDB. Defaults to {\"index_type\": \"FLAT\",\n                            \"field_name\": \"vector\", \"metric_type\": \"IP\", \"params\": {}}.\n    USER (str): The username for authentication with MilvusDB.\n    PASSWORD (SecretStr): The password for authentication with MilvusDB.\n    SECURED (bool): Indicates whether the connection to MilvusDB is secured. Defaults to False.\n\nMethods:\n    parse_json(cls, v): Validates and parses JSON strings into Python objects for SEARCH_PARAMS and INDEX_PARAMS.", "properties": {"HOST": {"default": "localhost", "title": "Host", "type": "string"}, "PORT": {"default": 19530, "exclusiveMinimum": 0, "maximum": 65535, "title": "Port", "type": "integer"}, "COLLECTION": {"title": "Collection", "type": "string"}, "COLLECTION_HISTORY_LEN": {"default": 10, "title": "Collection History Len", "type": "integer"}, "SEARCH_PARAMS": {"additionalProperties": true, "default": {"metric_type": "IP", "params": {}}, "title": "Search Params", "type": "object"}, "INDEX_PARAMS": {"additionalProperties": true, "default": {"index_type": "FLAT", "field_name": "vector", "metric_type": "IP", "params": {}}, "title": "Index Params", "type": "object"}, "USER": {"title": "User", "type": "string"}, "PASSWORD": {"format": "password", "title": "Password", "type": "string", "writeOnly": true}, "SECURED": {"default": false, "title": "Secured", "type": "boolean"}}, "required": ["COLLECTION", "USER", "PASSWORD"], "title": "MilvusSettings", "type": "object"}$kb1670c584e3849768830fe9c4d1e9ef9$::jsonb, $k77f62606d0524ed5afb8e39be9b8fc10${"type": "object", "title": "input", "x-wurzel-fqn": "pandera.typing.pandas.DataFrame[wurzel.steps.data.EmbeddingResult]"}$k77f62606d0524ed5afb8e39be9b8fc10$::jsonb, $kdaf02d557ea4435bb49f064df802a5ad${"description": "dummy output because its required to have a output data contract.", "properties": {"old": {"title": "Old", "type": "string"}, "new": {"title": "New", "type": "string"}}, "required": ["old", "new"], "title": "Result", "type": "object"}$kdaf02d557ea4435bb49f064df802a5ad$::jsonb, nullif('pandera.typing.pandas.DataFrame[wurzel.steps.data.EmbeddingResult]', '')::text, nullif('wurzel.steps.milvus.data.Result', '')::text, now()),
