_PARAMS": {"additionalProperties": true, "default": {"index_type": "FLAT", "field_name": "vector", "distance": "Dot", "params": {}}, "title": "Index Params", "type": "object"}, "APIKEY": {"default": "", "format": "password", "title": "Apikey", "type": "string", "writeOnly": true}, "REPLICATION_FACTOR": {"default": 3, "exclusiveMinimum": 0, "title": "Replication Factor", "type": "integer"}, "BATCH_SIZE": {"default": 1024, "exclusiveMinimum": 0, "title": "Batch Size", "type": "integer"}}, "required": ["COLLECTION"], "title": "QdrantSettings", "type": "object"}$k51a7a23b7728441696311d2834e20458$::jsonb, $k10ddec997c37468e850262cc05b3242c${"type": "object", "title": "input", "x-wurzel-fqn": "pandera.typing.pandas.DataFrame[wurzel.steps.data.EmbeddingResult]"}$k10ddec997c37468e850262cc05b3242c$::jsonb, $kb6bf217d3c1943a498017675fb0ee159${"type": "object", "title": "output", "x-wurzel-fqn": "pandera.typing.pandas.DataFrame[wurzel.steps.qdrant.data.QdrantResult]"}$kb6bf217d3c1943a498017675fb0ee159$::jsonb, nullif('pandera.typing.pandas.DataFrame[wurzel.steps.data.EmbeddingResult]', '')::text, nullif('pandera.typing.pandas.DataFrame[wurzel.steps.qdrant.data.QdrantResult]', '')::text, now()),
